import React, { useState } from "react";
import { useNavigate } from "react-router-dom";

function Register() {
    const navigate = useNavigate();

    const [formData, setFormData] = useState({
        name: "",
        email: "",
        dob: "",
        gender: "",
        address: "",
        phone: "",
        password: "",
        confirmPassword: ""
    });

    const [error, setError] = useState("");

    // Handle input change
    const handleChange = (e) => {
        setFormData({
            ...formData,
            [e.target.name]: e.target.value
        });
    };

    // Handle submit
    const handleSubmit = (e) => {
        e.preventDefault();
        setError("");

        // Validation
        if (!formData.name || !formData.email || !formData.password) {
            setError("Please fill all required fields");
            return;
        }

        if (formData.password.length < 6) {
            setError("Password must be at least 6 characters");
            return;
        }

        if (formData.password !== formData.confirmPassword) {
            setError("Passwords do not match");
            return;
        }

        // Save user (temporary)
        localStorage.setItem("user", JSON.stringify(formData));

        alert("Registration Successful!");

        // Navigate to login
        navigate("/login");
    };

    return (
        <div style={styles.container}>
            
            {/* Header */}
            <header style={styles.header}>
                <h2>DocBook</h2>
            </header>

            {/* Form Card */}
            <form style={styles.card} onSubmit={handleSubmit}>
                <h2 style={styles.title}>Create Account</h2>
                <p style={styles.subtitle}>Join DocBook</p>

                {error && <p style={styles.error}>{error}</p>}

                <div style={styles.row}>
                    <div style={styles.inputGroup}>
                        <label>Full Name</label>
                        <input name="name" type="text" onChange={handleChange} style={styles.input}/>
                    </div>

                    <div style={styles.inputGroup}>
                        <label>Email</label>
                        <input name="email" type="email" onChange={handleChange} style={styles.input}/>
                    </div>
                </div>

                <div style={styles.row}>
                    <div style={styles.inputGroup}>
                        <label>Date of Birth</label>
                        <input name="dob" type="date" onChange={handleChange} style={styles.input}/>
                    </div>

                    <div style={styles.inputGroup}>
                        <label>Gender</label>
                        <select name="gender" onChange={handleChange} style={styles.input}>
                            <option value="">Select</option>
                            <option>Male</option>
                            <option>Female</option>
                            <option>Other</option>
                        </select>
                    </div>
                </div>

                <div style={styles.inputGroup}>
                    <label>Address</label>
                    <textarea name="address" onChange={handleChange} style={styles.input}></textarea>
                </div>

                <div style={styles.inputGroup}>
                    <label>Contact Number</label>
                    <input name="phone" type="tel" onChange={handleChange} style={styles.input}/>
                </div>

                <div style={styles.row}>
                    <div style={styles.inputGroup}>
                        <label>Password</label>
                        <input name="password" type="password" onChange={handleChange} style={styles.input}/>
                    </div>

                    <div style={styles.inputGroup}>
                        <label>Confirm Password</label>
                        <input name="confirmPassword" type="password" onChange={handleChange} style={styles.input}/>
                    </div>
                </div>

                <button type="submit" style={styles.button}>
                    Sign Up
                </button>

                <p style={styles.footerText}>
                    Already have an account?{" "}
                    <span style={styles.link} onClick={() => navigate("/login")}>
                        Login
                    </span>
                </p>
            </form>
        </div>
    );
}

export default Register;

// Styles
const styles = {
    container: {
        minHeight: "100vh",
        backgroundColor: "#f4f6f9",
        display: "flex",
        flexDirection: "column",
        alignItems: "center"
    },

    header: {
        width: "100%",
        backgroundColor: "#2c3e50",
        color: "white",
        padding: "15px",
        textAlign: "center",
        marginBottom: "20px"
    },

    card: {
        width: "450px",
        background: "#fff",
        padding: "30px",
        borderRadius: "12px",
        boxShadow: "0 6px 15px rgba(0,0,0,0.1)"
    },

    title: {
        textAlign: "center",
        marginBottom: "5px",
        color: "#2c3e50"
    },

    subtitle: {
        textAlign: "center",
        marginBottom: "20px",
        color: "#7f8c8d"
    },

    error: {
        color: "red",
        textAlign: "center",
        marginBottom: "10px",
        fontSize: "14px"
    },

    row: {
        display: "flex",
        gap: "10px"
    },

    inputGroup: {
        display: "flex",
        flexDirection: "column",
        marginBottom: "15px",
        flex: 1
    },

    input: {
        padding: "10px",
        borderRadius: "5px",
        border: "1px solid #ccc",
        marginTop: "5px",
        fontSize: "14px"
    },

    button: {
        width: "100%",
        padding: "12px",
        backgroundColor: "#2c3e50",
        color: "white",
        border: "none",
        borderRadius: "6px",
        fontSize: "16px",
        cursor: "pointer",
        marginTop: "10px"
    },

    footerText: {
        textAlign: "center",
        marginTop: "15px",
        fontSize: "14px"
    },

    link: {
        color: "#2c3e50",
        fontWeight: "bold",
        cursor: "pointer",
        marginLeft: "5px"
    }
};
